from dataclasses import dataclass

@dataclass
class HardwareSpec:
    num_qubits: int
    t2_microseconds: float
    two_qubit_error: float
    gate_time_ns: float

class HardwareAnalyzer:
    def __init__(self, spec: HardwareSpec):
        self.spec = spec

    def max_circuit_depth(self) -> int:
        coherence_ns = self.spec.t2_microseconds * 1000
        max_gates = int(coherence_ns / self.spec.gate_time_ns * 0.5)
        return max_gates

    def effective_qubits(self, error_budget: float = 0.1) -> int:
        cumulative_error = 0
        usable = 0
        for _ in range(self.spec.num_qubits):
            cumulative_error = 1 - (1 - cumulative_error) * (1 - self.spec.two_qubit_error)
            if cumulative_error < error_budget:
                usable += 1
            else:
                break
        return usable

    def problem_size_limit(self, gates_per_var: int = 10) -> int:
        max_depth = self.max_circuit_depth()
        effective = self.effective_qubits()
        return min(effective, max_depth // gates_per_var)

import numpy as np
from typing import List, Tuple

class ZeroNoiseExtrapolator:
    def extrapolate(self, results: List[float], scale_factors: List[float]) -> Tuple[float, float]:
        coeffs = np.polyfit(scale_factors, results, 1)
        mitigated = coeffs[1]  # y-intercept (x=0)
        # Confidence based on slope magnitude
        confidence = max(0, 1 - abs(coeffs[0]))
        return (mitigated, confidence)

    def richardson_extrapolation(self, results: List[float], scale_factors: List[float]) -> float:
        if len(results) < 3:
            return self.extrapolate(results, scale_factors)[0]

        # For scale factors [1, 2, 3], use Richardson formula
        c1, c2, c3 = scale_factors[0], scale_factors[1], scale_factors[2]
        r1, r2, r3 = results[0], results[1], results[2]

        # First-order Richardson between pairs
        r12 = (c2 * r1 - c1 * r2) / (c2 - c1)
        r23 = (c3 * r2 - c2 * r3) / (c3 - c2)

        # Second-order
        if abs(c3 - c1) > 1e-10:
            return (c3 * r12 - c1 * r23) / (c3 - c1)
        return r12

from typing import Dict, Any

class QuantumBridge:
    def __init__(self, num_assets: int):
        self.num_assets = num_assets

    def prepare_quantum_input(self, portfolio_data: Dict) -> Dict:
        returns = portfolio_data.get('returns', [])
        covariance = portfolio_data.get('covariance', [])

        max_return = max(abs(r) for r in returns) if returns else 1
        normalized_returns = [r / max_return for r in returns]

        return {
            'normalized_returns': normalized_returns,
            'covariance': covariance,
            'normalization_factor': max_return,
            'num_qubits_estimated': len(returns) * 2
        }

    def process_quantum_output(self, quantum_result: Dict) -> Dict:
        weights = quantum_result.get('weights', [])

        # Ensure non-negative
        weights = [max(0, w) for w in weights]

        # Normalize to sum to 1
        total = sum(weights)
        if total > 0:
            weights = [w / total for w in weights]
        else:
            n = len(weights)
            weights = [1/n] * n if n > 0 else []

        return {
            'portfolio_weights': weights,
            'iterations': quantum_result.get('iterations', 0),
            'quality': quantum_result.get('energy', 0)
        }

