from dataclasses import dataclass
from typing import Dict, List

@dataclass
class SkillGap:
    skill: str
    required: int
    available: int
    scarcity: float

class TalentPlanner:
    def __init__(self):
        self.gaps: List[SkillGap] = []

    def add_gap(self, gap: SkillGap):
        self.gaps.append(gap)

    def gap_analysis(self) -> Dict[str, Dict]:
        result = {}
        for g in self.gaps:
            gap_count = max(0, g.required - g.available)
            result[g.skill] = {
                'gap': gap_count,
                'hiring_difficulty': gap_count * g.scarcity,
                'urgency': 'high' if gap_count > 2 else 'medium' if gap_count > 0 else 'low'
            }
        return result

    def recommend_strategy(self, budget: float) -> List[Dict]:
        # Hiring cost: 200k * scarcity, Training cost: 50k
        recommendations = []
        remaining = budget

        for g in sorted(self.gaps, key=lambda x: x.scarcity):
            gap = max(0, g.required - g.available)
            if gap == 0:
                continue

            hire_cost = 200000 * g.scarcity * gap
            train_cost = 50000 * gap

            if g.scarcity > 0.7:
                strategy = 'hire'
                cost = hire_cost
            else:
                strategy = 'train'
                cost = train_cost

            if cost <= remaining:
                recommendations.append({
                    'skill': g.skill,
                    'strategy': strategy,
                    'cost': cost,
                    'gap_to_fill': gap
                })
                remaining -= cost

        return recommendations

