from dataclasses import dataclass
from typing import Dict, List

@dataclass
class SecurityControl:
    name: str
    threat: str
    cost: float
    effectiveness: float

class SecurityAnalyzer:
    def __init__(self):
        self.controls: List[SecurityControl] = []
        self.threat_levels: Dict[str, float] = {}

    def add_control(self, control: SecurityControl):
        self.controls.append(control)

    def set_threat_level(self, threat: str, level: float):
        self.threat_levels[threat] = level

    def residual_risk(self, threat: str) -> float:
        base_risk = self.threat_levels.get(threat, 0.5)
        relevant = [c for c in self.controls if c.threat == threat]

        reduction = 1.0
        for c in relevant:
            reduction *= (1 - c.effectiveness)

        return base_risk * reduction

    def recommend_controls(self, budget: float) -> List[Dict]:
        recommendations = []
        remaining = budget

        scored = []
        for c in self.controls:
            risk_before = self.threat_levels.get(c.threat, 0.5)
            risk_reduction = risk_before * c.effectiveness
            score = risk_reduction / c.cost if c.cost > 0 else 0
            scored.append((c, score, risk_reduction))

        for c, score, reduction in sorted(scored, key=lambda x: x[1], reverse=True):
            if c.cost <= remaining:
                recommendations.append({
                    'control': c.name,
                    'cost': c.cost,
                    'risk_reduction': reduction
                })
                remaining -= c.cost

        return recommendations
